    },
    {
        "role": "bullet",
        "segment": "programming languages such as Fortran, COBOL, Turbo Pascal, Visual Basic",
        "citations": [
            {
                "type": "source_text",
                "content": "The January/February 2000 issue of IEEE Software contains an editorial by McConnell about software engineering's best influences: programming languages: Fortran, COBOL,Turbo Pascal,Visual Basic",
                "img_id": null
