        ]
    },
    {
        "role": "bullet",
        "segment": "Capability Maturity Model for software",
        "citations": [
            {
                "type": "source_text",
                "content": "The January/February 2000 issue of IEEE Software contains an editorial by McConnell about software engineering's best influences: Capability Maturity Model for software",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
        "segment": "component-based development",
        "citations": [
            {
                "type": "source_text",
                "content": "The January/February 2000 issue of IEEE Software contains an editorial by McConnell about software engineering's best influences: component-based development",
                "img_id": null
            }
        ]
    },
    {
        "role": "bullet",
        "segment": "metrics and measurement",
        "citations": [
            {
                "type": "source_text",
                "content": "The January/February 2000 issue of IEEE Software contains an editorial by McConnell about software engineering's best influences: metrics and measurement",
                "img_id": null
